func (p *Poller) Run(ctx context.Context) {
    ticker := time.NewTicker(p.Interval) defer ticker.Stop() for {
        select {
            case <-ctx.Done(): return case <-ticker.C: p.OnTick(ctx)
        }
    }
}

func Register(lc fx.Lifecycle, svc Service) {
